glibc socket函数介绍我们使用的socket函数，原型如下。代码位置为：&#x2F;usr&#x2F;include&#x2F;x86_64-linux-gnu&#x2F;sys&#x2F;socket.h
int socket(int domain, int type, int protocol);




参数
介绍



domain
指定一个通讯域名；选择的协议将会用于通讯。如 AF_INET、AF_NETLINK、AF_PACKET、AF_UNIX


type
套接字通过 type, 参数来确定通信语义。如：SOCK_STREAM、SOCK_DGRAM、SOCK_RAW


protocol
指定一个协议用于套接字。如 IPPROTO_TCP、IPPROTO_UDP、IPPROTO_ICMP、IPPROTO_IP


而socket函数是glibc中提供的函数，我们看下glibc中的socket函数实现。代码位置在：glibc-2.41&#x2F;sysdeps&#x2F;unix&#x2F;sysv&#x2F;linux&#x2F;socket.c
#include &lt;sys/socket.h&gt;#include &lt;socketcall.h&gt;int__socket (int fd, int type, int domain)&#123;#ifdef __ASSUME_SOCKET_SYSCALL  return INLINE_SYSCALL_CALL (socket, fd, type, domain);#else  return SOCKETCALL (socket, fd, type, domain);#endif&#125;libc_hidden_def (__socket)weak_alias (__socket, socket)

我们在syscall调用流程分析中，已经了解到了，glibc中的socket函数几乎什么都没做，可以理解为仅仅是内核socket系统调用(__do_sys_socket)的一个封装。
socket系统调用我们首先来看下socket系统调用的入口。可以看到__do_sys_socket，什么都没做，只是再次调用了__sys_socket。
/* __do_sys_socket */SYSCALL_DEFINE3(socket, int, family, int, type, int, protocol)&#123;	return __sys_socket(family, type, protocol);&#125;

从__sys_socket中可以看到，主要调用了__sys_socket_create与sock_map_fd函数。
/* 只由 __do_sys_socket 、 __do_sys_socketcall 调用  * 负责根据传入的三个参数，创建出 socket_alloc 结构，并映射出fd返给外围 */int __sys_socket(int family, int type, int protocol)&#123;	struct socket *sock;	int flags;	/* 申请 socket_alloc 结构，并初始化，但是注意这里返回的只是其中的socket */	sock = __sys_socket_create(family, type,				   update_socket_protocol(family, type, protocol));	if (IS_ERR(sock))		return PTR_ERR(sock);	/* 不关心低4bit sock的type */	flags = type &amp; ~SOCK_TYPE_MASK;	if (SOCK_NONBLOCK != O_NONBLOCK &amp;&amp; (flags &amp; SOCK_NONBLOCK)) &#123;		/* 清位之后置位 */		flags = (flags &amp; ~SOCK_NONBLOCK) | O_NONBLOCK;	&#125;	/* 将 socket 映射出一个对应的文件描述符fd，返给上层应用 */	return sock_map_fd(sock, flags &amp; (O_CLOEXEC | O_NONBLOCK));&#125;


我们先看__sys_socket_create做了什么。可以看到，只是做了下参数检查及标志位校验等，然后调用sock_create。
/* 由 __sys_socket 调用  * 负责创建出 socket_alloc 结构 */static struct socket *__sys_socket_create(int family, int type, int protocol)&#123;	struct socket *sock;	int retval;	/* Check the SOCK_* constants for consistency.  	 * 编译器一致性检查 */	BUILD_BUG_ON(SOCK_CLOEXEC != O_CLOEXEC);	BUILD_BUG_ON((SOCK_MAX | SOCK_TYPE_MASK) != SOCK_TYPE_MASK);	BUILD_BUG_ON(SOCK_CLOEXEC &amp; SOCK_TYPE_MASK);	BUILD_BUG_ON(SOCK_NONBLOCK &amp; SOCK_TYPE_MASK);	/* 标志位校验 */	if ((type &amp; ~SOCK_TYPE_MASK) &amp; ~(SOCK_CLOEXEC | SOCK_NONBLOCK))		return ERR_PTR(-EINVAL);	/* 提取真正的类型，我们只关心它的低位的1个字节 */	type &amp;= SOCK_TYPE_MASK;	retval = sock_create(family, type, protocol, &amp;sock);	if (retval &lt; 0)		return ERR_PTR(retval);	return sock;&#125;


这里sock_create仅是封装了下__sock_create。__sock_create中有对family和type的检查，有过lsm相关的钩子点。核心的是sock_alloc、及pf-&gt;create(对于AF_INET，就是inet_create)。
int sock_create(int family, int type, int protocol, struct socket **res)&#123;	return __sock_create(current-&gt;nsproxy-&gt;net_ns, family, type, protocol, res, 0);&#125;int __sock_create(struct net *net, int family, int type, int protocol,			 struct socket **res, int kern)&#123;	int err;	struct socket *sock;	const struct net_proto_family *pf;	/*	 *      Check protocol is in range	 *      合法性检查	 */	if (family &lt; 0 || family &gt;= NPROTO)		return -EAFNOSUPPORT;	if (type &lt; 0 || type &gt;= SOCK_MAX)		return -EINVAL;	/* Compatibility.	   This uglymoron is moved from INET layer to here to avoid deadlock in module load.	   过时的 PF_INET + SOCK_PACKET 参数组合 转换为 现代支持的 PF_PACKET 协议族	 */	if (family == PF_INET &amp;&amp; type == SOCK_PACKET) &#123;		pr_info_once(&quot;%s uses obsolete (PF_INET,SOCK_PACKET)\n&quot;,			     current-&gt;comm);		family = PF_PACKET;	&#125;	/* lsm socket_create hook点 */	err = security_socket_create(family, type, protocol, kern);	if (err)		return err;	/*	 *	Allocate the socket and allow the family to set things up. if	 *	the protocol is 0, the family is instructed to select an appropriate	 *	default.	 *  申请 socket_alloc 结构，返回的是其中的 socket 成员地址，	 *  这里 socket-&gt;sk 还没初始化，是在底下的 pf-&gt;create 里面创建的	 */	sock = sock_alloc();	if (!sock) &#123;		net_warn_ratelimited(&quot;socket: no more sockets\n&quot;);		return -ENFILE;	/* Not exactly a match, but its the				   closest posix thing */	&#125;	/* 这里的type是用户创建socket传入的第二参数的type */	sock-&gt;type = type;#ifdef CONFIG_MODULES	/* Attempt to load a protocol module if the find failed.	 *	 * 12/09/1996 Marcin: But! this makes REALLY only sense, if the user	 * requested real, full-featured networking support upon configuration.	 * Otherwise module support will break!	 * net_families 存储的是 AF_INET 对应的 net_proto_family	 * 是在 inet_init 中，通过 sock_register 注册的 inet_family_ops	 */	if (rcu_access_pointer(net_families[family]) == NULL)		request_module(&quot;net-pf-%d&quot;, family);#endif	rcu_read_lock();	/* 从sock_register数组中找到一个元素pf，这个pf中有一个create()回调函数，	 * 这个回调函数就是family类型(such as AF_INET)需要的create函数。 */	pf = rcu_dereference(net_families[family]);	err = -EAFNOSUPPORT;	if (!pf)		goto out_release;	/*	 * We will call the -&gt;create function, that possibly is in a loadable	 * module, so we have to bump that loadable module refcnt first.	 * 增加引用计数，有些family可能是以模块方式加载的，比如 nf_conntrack	 */	if (!try_module_get(pf-&gt;owner))		goto out_release;	/* Now protected by module ref count */	rcu_read_unlock();	/* inet_create 、 inet6_create 	 * 如果用户指定的family类型是AF_INET, 那这个函数就是调用的inet_create，	 * 这里面将真正的创建 socket-&gt;sk，并且给 socket 的部分成员初始化 */	err = pf-&gt;create(net, sock, protocol, kern);	if (err &lt; 0)		goto out_module_put;	/*	 * Now to bump the refcnt of the [loadable] module that owns this	 * socket at sock_release time we decrement its refcnt.	 */	if (!try_module_get(sock-&gt;ops-&gt;owner))		goto out_module_busy;	/*	 * Now that we&#x27;re done with the -&gt;create function, the [loadable]	 * module can have its refcnt decremented	 * 减引用计数	 */	module_put(pf-&gt;owner);	/* lsm socket_post_create hook点 */	err = security_socket_post_create(sock, family, type, protocol, kern);	if (err)		goto out_sock_release;	*res = sock;	return 0;out_module_busy:	err = -EAFNOSUPPORT;out_module_put:	sock-&gt;ops = NULL;	module_put(pf-&gt;owner);out_sock_release:	sock_release(sock);	return err;out_release:	rcu_read_unlock();	goto out_sock_release;&#125;


sock_alloc函数就是申请了一个socket_alloc的结构，只是返回的是其中的socket地址。
struct socket *sock_alloc(void)&#123;	struct inode *inode;	struct socket *sock;	/* 调用socket文件系统的超级块的ops申请一个inode，申请的其实是 socket_alloc 结构 */	inode = new_inode_pseudo(sock_mnt-&gt;mnt_sb);	if (!inode)		return NULL;	/* 通过 container_of 取与 inode 相邻的 socket 地址 */	sock = SOCKET_I(inode);	inode-&gt;i_ino = get_next_ino(); /* 分配唯一的inode编号 */	inode-&gt;i_mode = S_IFSOCK | S_IRWXUGO; /* 文件类型 */	inode-&gt;i_uid = current_fsuid();	inode-&gt;i_gid = current_fsgid();	inode-&gt;i_op = &amp;sockfs_inode_ops; /* 绑定ops */	return sock;&#125;struct inode *new_inode_pseudo(struct super_block *sb)&#123;	struct inode *inode = alloc_inode(sb);	if (inode) &#123;		spin_lock(&amp;inode-&gt;i_lock);		inode-&gt;i_state = 0;		spin_unlock(&amp;inode-&gt;i_lock);	&#125;	return inode;&#125;/* 由 new_inode_pseudo 调用 */static struct inode *alloc_inode(struct super_block *sb)&#123;	const struct super_operations *ops = sb-&gt;s_op;	struct inode *inode;	/* 对于socket来说，调用的是 sockfs_ops 的 sock_alloc_inode	 * sock_alloc_inode 会创建真正的 socket_alloc 结构 */	if (ops-&gt;alloc_inode)		inode = ops-&gt;alloc_inode(sb);	else		inode = alloc_inode_sb(sb, inode_cachep, GFP_KERNEL);	if (!inode)		return NULL;	if (unlikely(inode_init_always(sb, inode))) &#123;		if (ops-&gt;destroy_inode) &#123;			ops-&gt;destroy_inode(inode);			if (!ops-&gt;free_inode)				return NULL;		&#125;		inode-&gt;free_inode = ops-&gt;free_inode;		i_callback(&amp;inode-&gt;i_rcu);		return NULL;	&#125;	return inode;&#125;/* 由 alloc_inode 调用  * 申请socket_alloc结构，并初始化成员 */static struct inode *sock_alloc_inode(struct super_block *sb)&#123;	struct socket_alloc *ei;	ei = alloc_inode_sb(sb, sock_inode_cachep, GFP_KERNEL);	if (!ei)		return NULL;	init_waitqueue_head(&amp;ei-&gt;socket.wq.wait);	ei-&gt;socket.wq.fasync_list = NULL;	ei-&gt;socket.wq.flags = 0;	ei-&gt;socket.state = SS_UNCONNECTED;	ei-&gt;socket.flags = 0;	ei-&gt;socket.ops = NULL;	ei-&gt;socket.sk = NULL;	ei-&gt;socket.file = NULL;	return &amp;ei-&gt;vfs_inode;&#125;

socket_alloc结构如下所示。
/* sock_alloc_inode 申请并初始化 */struct socket_alloc &#123;	struct socket socket;	struct inode vfs_inode;&#125;;

socket结构如下所示。其中最为核心的是sock结构。对于tcp来说，它其实指向的是tcp_sock，对于udp来说，指向的是udp_sock。pf-&gt;create就是根据type和protocol，来创建对应的sock结构。
struct socket &#123;	/* such as SS_UNCONNECTED  、 SS_CONNECTED */	socket_state		state;		/* socket()的第二个参数， __sock_create 中赋值， SOCK_STREAM 、 SOCK_DGRAM 、 SOCK_RAW 等*/	short			type;			unsigned long		flags;	/* sock_alloc_file 中申请、初始化，并赋值 */	struct file		*file;			/* inet_create 中申请，申请的大小为 prot-&gt;obj_size	 * sock_init_data_uid 中赋值，指向type对应申请出来的sock结构 */	struct sock		*sk;			/* Might change with IPV6_ADDRFORM or MPTCP. 	 * 套接口层操作集合, such as inet_stream_ops 、 inet_dgram_ops、 inet_sockraw_ops */	const struct proto_ops	*ops;	struct socket_wq	wq;&#125;;


inet_create是socket系统调用中的核心函数，它将创建并初始化socket结构中的最核心的、最关键的sock结构。
/* *	Create an inet socket. *  由 __sock_create 调用， *  这里主要是做 socket-&gt;sk 的创建，及 socket 的部分成员的初始化 */static int inet_create(struct net *net, struct socket *sock, int protocol,		       int kern)&#123;	struct sock *sk;	struct inet_protosw *answer;	struct inet_sock *inet;	struct proto *answer_prot;	unsigned char answer_flags;	int try_loading_module = 0;	int err;	/* 协议有效性校验 */	if (protocol &lt; 0 || protocol &gt;= IPPROTO_MAX)		return -EINVAL;	/* 正在创建socket，因此此时状态还是未连接 */	sock-&gt;state = SS_UNCONNECTED;	/* Look for the requested type/protocol pair. */lookup_protocol:	err = -ESOCKTNOSUPPORT;	rcu_read_lock();	/* 其实就是把 inetsw_array 中的成员，根据 type 挂在了 inetsw 的链表上 */	list_for_each_entry_rcu(answer, &amp;inetsw[sock-&gt;type], list) &#123;		err = 0;		/* Check the non-wild match. */		if (protocol == answer-&gt;protocol) &#123;			if (protocol != IPPROTO_IP)				break;		&#125; else &#123;			/* Check for the two wild cases. */			if (IPPROTO_IP == protocol) &#123;				protocol = answer-&gt;protocol;				break;			&#125;			if (IPPROTO_IP == answer-&gt;protocol)				break;		&#125;		err = -EPROTONOSUPPORT;	&#125;	if (unlikely(err)) &#123;		if (try_loading_module &lt; 2) &#123;			rcu_read_unlock();			/*			 * Be more specific, e.g. net-pf-2-proto-132-type-1			 * (net-pf-PF_INET-proto-IPPROTO_SCTP-type-SOCK_STREAM)			 */			if (++try_loading_module == 1)				request_module(&quot;net-pf-%d-proto-%d-type-%d&quot;,					       PF_INET, protocol, sock-&gt;type);			/*			 * Fall back to generic, e.g. net-pf-2-proto-132			 * (net-pf-PF_INET-proto-IPPROTO_SCTP)			 */			else				request_module(&quot;net-pf-%d-proto-%d&quot;,					       PF_INET, protocol);			goto lookup_protocol;		&#125; else			goto out_rcu_unlock;	&#125;	err = -EPERM;	/* 如果是用户态来创建的，并且是SOCK_RAW，额外检查下权限 */	if (sock-&gt;type == SOCK_RAW &amp;&amp; !kern &amp;&amp;	    !ns_capable(net-&gt;user_ns, CAP_NET_RAW))		goto out_rcu_unlock;	/* such as inet_stream_ops 、 inet_dgram_ops、 inet_sockraw_ops */	sock-&gt;ops = answer-&gt;ops;	/* such as tcp_prot 、 udp_prot 、ping_prot 、raw_prot */	answer_prot = answer-&gt;prot;	/* see inetsw_array */	answer_flags = answer-&gt;flags;	rcu_read_unlock();	WARN_ON(!answer_prot-&gt;slab);	err = -ENOMEM;	/* 根据 prot-&gt;obj_size 来申请 sock 的内存, sk 其实就是 tcp_sock 、 udp_sock	 * tcp_sock		tcp_prot	sizeof(tcp_sock) 约2264字节	 * udp_sock		udp_prot  	sizeof(udp_sock) 约1152字节 */	sk = sk_alloc(net, PF_INET, GFP_KERNEL, answer_prot, kern);	if (!sk)		goto out;	err = 0;	/* icmp_prot 、 raw_prot 才有标志里才有这个 */	if (INET_PROTOSW_REUSE &amp; answer_flags)		sk-&gt;sk_reuse = SK_CAN_REUSE;	inet = inet_sk(sk);	inet_assign_bit(IS_ICSK, sk, INET_PROTOSW_ICSK &amp; answer_flags);	inet_clear_bit(NODEFRAG, sk);	if (SOCK_RAW == sock-&gt;type) &#123;		inet-&gt;inet_num = protocol;		if (IPPROTO_RAW == protocol)			inet_set_bit(HDRINCL, sk);	&#125;	if (READ_ONCE(net-&gt;ipv4.sysctl_ip_no_pmtu_disc))		inet-&gt;pmtudisc = IP_PMTUDISC_DONT;	else		inet-&gt;pmtudisc = IP_PMTUDISC_WANT;	atomic_set(&amp;inet-&gt;inet_id, 0);	sock_init_data(sock, sk);	sk-&gt;sk_destruct	   = inet_sock_destruct;	sk-&gt;sk_protocol	   = protocol;	sk-&gt;sk_backlog_rcv = sk-&gt;sk_prot-&gt;backlog_rcv;	sk-&gt;sk_txrehash = READ_ONCE(net-&gt;core.sysctl_txrehash);	inet-&gt;uc_ttl	= -1;	inet_set_bit(MC_LOOP, sk);	inet-&gt;mc_ttl	= 1;	inet_set_bit(MC_ALL, sk);	inet-&gt;mc_index	= 0;	inet-&gt;mc_list	= NULL;	inet-&gt;rcv_tos	= 0;	/* SOCK_RAW 才会走进这里，因为前面只有 SOCK_RAW 才给 inet_num 赋值了啊 */	if (inet-&gt;inet_num) &#123;		/* It assumes that any protocol which allows		 * the user to assign a number at socket		 * creation time automatically shares.		 */		inet-&gt;inet_sport = htons(inet-&gt;inet_num);		/* Add to protocol hash chains.		 * raw_hash_sk */		err = sk-&gt;sk_prot-&gt;hash(sk);		if (err) &#123;			sk_common_release(sk);			goto out;		&#125;	&#125;	/* tcp_v4_init_sock 、 udp_init_sock 	 * 负责对应套接字初始化相关 */	if (sk-&gt;sk_prot-&gt;init) &#123;		err = sk-&gt;sk_prot-&gt;init(sk);		if (err) &#123;			sk_common_release(sk);			goto out;		&#125;	&#125;	/* 用户态socket()调过来，kern是0, 可以看 sock_create 	 * 如果是内核创建套接字，kern是1，就不再走bpf相关钩子了 */	if (!kern) &#123;		err = BPF_CGROUP_RUN_PROG_INET_SOCK(sk);		if (err) &#123;			sk_common_release(sk);			goto out;		&#125;	&#125;out:	return err;out_rcu_unlock:	rcu_read_unlock();	goto out;&#125;

/* NOTE: A lot of things set to zero explicitly by call to *       sk_alloc() so need not be done here. * 由 inet_create 调用 * 这是tcp socket初始化必经之路 */static int tcp_v4_init_sock(struct sock *sk)&#123;	struct inet_connection_sock *icsk = inet_csk(sk);	tcp_init_sock(sk);	icsk-&gt;icsk_af_ops = &amp;ipv4_specific;#ifdef CONFIG_TCP_MD5SIG	tcp_sk(sk)-&gt;af_specific = &amp;tcp_sock_ipv4_specific;#endif	return 0;&#125;/* Address-family independent initialization for a tcp_sock. * * NOTE: A lot of things set to zero explicitly by call to *       sk_alloc() so need not be done here. * 由 tcp_v4_init_sock 、 tcp_v6_init_sock 调用 */void tcp_init_sock(struct sock *sk)&#123;	struct inet_connection_sock *icsk = inet_csk(sk);	struct tcp_sock *tp = tcp_sk(sk);	tp-&gt;out_of_order_queue = RB_ROOT;	sk-&gt;tcp_rtx_queue = RB_ROOT;	/* 初始化定时器相关 */	tcp_init_xmit_timers(sk);		INIT_LIST_HEAD(&amp;tp-&gt;tsq_node);	INIT_LIST_HEAD(&amp;tp-&gt;tsorted_sent_queue);	icsk-&gt;icsk_rto = TCP_TIMEOUT_INIT;	icsk-&gt;icsk_rto_min = TCP_RTO_MIN;	icsk-&gt;icsk_delack_max = TCP_DELACK_MAX;	tp-&gt;mdev_us = jiffies_to_usecs(TCP_TIMEOUT_INIT);	minmax_reset(&amp;tp-&gt;rtt_min, tcp_jiffies32, ~0U);	/* So many TCP implementations out there (incorrectly) count the	 * initial SYN frame in their delayed-ACK and congestion control	 * algorithms that we must have the following bandaid to talk	 * efficiently to them.  -DaveM	 */	tcp_snd_cwnd_set(tp, TCP_INIT_CWND);	/* There&#x27;s a bubble in the pipe until at least the first ACK. */	tp-&gt;app_limited = ~0U;	tp-&gt;rate_app_limited = 1;	/* See draft-stevens-tcpca-spec-01 for discussion of the	 * initialization of these values.	 */	tp-&gt;snd_ssthresh = TCP_INFINITE_SSTHRESH;	tp-&gt;snd_cwnd_clamp = ~0;	tp-&gt;mss_cache = TCP_MSS_DEFAULT;	tp-&gt;reordering = READ_ONCE(sock_net(sk)-&gt;ipv4.sysctl_tcp_reordering);	tcp_assign_congestion_control(sk);	tp-&gt;tsoffset = 0;	tp-&gt;rack.reo_wnd_steps = 1;	sk-&gt;sk_write_space = sk_stream_write_space;	sock_set_flag(sk, SOCK_USE_WRITE_QUEUE);	icsk-&gt;icsk_sync_mss = tcp_sync_mss;	/* 默认 tcp_sock 发送缓冲区大小:16384(16K) 	接收缓冲区大小:131072(128K)	 * net.ipv4.tcp_wmem = 4096        16384   4194304 	 * net.ipv4.tcp_rmem = 4096        131072  6291456 */	WRITE_ONCE(sk-&gt;sk_sndbuf, READ_ONCE(sock_net(sk)-&gt;ipv4.sysctl_tcp_wmem[1]));	WRITE_ONCE(sk-&gt;sk_rcvbuf, READ_ONCE(sock_net(sk)-&gt;ipv4.sysctl_tcp_rmem[1]));	/* 初始化用于调整TCP接收窗口大小的缩放比例因子 */	tcp_scaling_ratio_init(sk);	/* 表示该sk支持零拷贝操作，通常用于优化网络数据传输	 * 减少数据在内核和用户空间之间的拷贝次数 */	set_bit(SOCK_SUPPORT_ZC, &amp;sk-&gt;sk_socket-&gt;flags);	/* 增加 tcp_sock 的引用计数，确保其在使用期间不会被释放	 * 在 tcp_v4_destroy_sock 中关闭tcp_sock时，会减引用计数 */	sk_sockets_allocated_inc(sk);&#125;EXPORT_SYMBOL(tcp_init_sock);


我们已经申请好了socket结构，而socket结构对于用户态是无感的，用户态是通过文件描述符fd来管理对应的socket结构的。因此就需要将socket映射出一个与之对应的文件描述符fd，返回给上层应用，sock_map_fd就是做这件事情的。它首先通过get_unused_fd_flags获取当前进程的最小的未使用的文件描述符fd，然后调用sock_alloc_file创建一个文件对象，再通过fd_install，完成fd 和 文件对象的关联。而文件对象也是跟socket相互关联的。
/* 由 __sys_socket 调用 */static int sock_map_fd(struct socket *sock, int flags)&#123;	struct file *newfile;	int fd;	/* 获取当前进程的一个未使用的文件描述符fd */	fd = get_unused_fd_flags(flags);	if (unlikely(fd &lt; 0)) &#123;		sock_release(sock);		return fd;	&#125;	/* 创建一个文件对象，将 socket 和 file 关联起来 */	newfile = sock_alloc_file(sock, flags, NULL);	if (!IS_ERR(newfile)) &#123;		/* 关联 fd 和 file，这样找到了 file，也就找到了 socket */		fd_install(fd, newfile);		return fd;	&#125;	/* 有错误，将fd标记为未使用 */	put_unused_fd(fd);	return PTR_ERR(newfile);&#125;


get_unused_fd_flags就是通过current(进程pcb结构)，拿到其中的files，这个files就是来管理这个进程所有的文件描述符的结构。files内部有一个fdt，fdt内部有一个二维指针fd，这个二维指针指向了fd array。用户态的fd其实就是这个fd array的数组索引。
/* 由 sock_map_fd 调用 */int get_unused_fd_flags(unsigned flags)&#123;	return __get_unused_fd_flags(flags, rlimit(RLIMIT_NOFILE));&#125;EXPORT_SYMBOL(get_unused_fd_flags);int __get_unused_fd_flags(unsigned flags, unsigned long nofile)&#123;	return alloc_fd(0, nofile, flags);&#125;/* * allocate a file descriptor, mark it busy. */static int alloc_fd(unsigned start, unsigned end, unsigned flags)&#123;	struct files_struct *files = current-&gt;files;	unsigned int fd;	int error;	struct fdtable *fdt;	spin_lock(&amp;files-&gt;file_lock);repeat:	fdt = files_fdtable(files);	fd = start;	if (fd &lt; files-&gt;next_fd)		fd = files-&gt;next_fd;	if (fd &lt; fdt-&gt;max_fds)		fd = find_next_fd(fdt, fd);	/*	 * N.B. For clone tasks sharing a files structure, this test	 * will limit the total number of files that can be opened.	 */	error = -EMFILE;	if (fd &gt;= end)		goto out;	error = expand_files(files, fd);	if (error &lt; 0)		goto out;	/*	 * If we needed to expand the fs array we	 * might have blocked - try again.	 */	if (error)		goto repeat;	if (start &lt;= files-&gt;next_fd)		files-&gt;next_fd = fd + 1;	__set_open_fd(fd, fdt);	if (flags &amp; O_CLOEXEC)		__set_close_on_exec(fd, fdt);	else		__clear_close_on_exec(fd, fdt);	error = fd;#if 1	/* Sanity check */	if (rcu_access_pointer(fdt-&gt;fd[fd]) != NULL) &#123;		printk(KERN_WARNING &quot;alloc_fd: slot %d not NULL!\n&quot;, fd);		rcu_assign_pointer(fdt-&gt;fd[fd], NULL);	&#125;#endifout:	spin_unlock(&amp;files-&gt;file_lock);	return error;&#125;/* * Open file table structure */struct files_struct &#123;  /*   * read mostly part   */	atomic_t count;	bool resize_in_progress;	wait_queue_head_t resize_wait;	/* 所有的文件描述符都在fdt的fd数组里存着 */	struct fdtable __rcu *fdt;	struct fdtable fdtab;  /*   * written part on a separate cache line in SMP   */	spinlock_t file_lock ____cacheline_aligned_in_smp;	unsigned int next_fd;	unsigned long close_on_exec_init[1];	unsigned long open_fds_init[1];	unsigned long full_fds_bits_init[1];	struct file __rcu * fd_array[NR_OPEN_DEFAULT];&#125;;struct fdtable &#123;	unsigned int max_fds;	struct file __rcu **fd;      /* current fd array */	unsigned long *close_on_exec;	unsigned long *open_fds;	unsigned long *full_fds_bits;	struct rcu_head rcu;&#125;;


sock_alloc_file会申请一个file对象，并且它将与socket互相指向对方，这就意味着找到其中一个，就可以找到另外一个。
struct file *sock_alloc_file(struct socket *sock, int flags, const char *dname)&#123;	struct file *file;	if (!dname)		dname = sock-&gt;sk ? sock-&gt;sk-&gt;sk_prot_creator-&gt;name : &quot;&quot;;	/* alloc 一个file 绑定了 socket_file_ops 回调函数集合，sock_mnt为一个挂载点 */	file = alloc_file_pseudo(SOCK_INODE(sock), sock_mnt, dname,				O_RDWR | (flags &amp; O_NONBLOCK),				&amp;socket_file_ops);	if (IS_ERR(file)) &#123;		sock_release(sock);		return file;	&#125;	file-&gt;f_mode |= FMODE_NOWAIT;	/* socket、file 互相指向对方 */	sock-&gt;file = file;	file-&gt;private_data = sock;	/* 标记为流式文件，不支持lseek(随机访问)？*/	stream_open(SOCK_INODE(sock), file);	return file;&#125;


fd_install就是将申请的file对象，按照获取到的fd，将file放到fdt的fd数组的fd索引位置处。这样后续用户态传入fd，就可以在这个fdt的fd数组中索引到file，而通过file就可以找到与之关联的socket结构。从而内核可以再对socket结构去做对应的操作。
/* * 由 sock_map_fd 、 __sys_accept4_file 调用 * 目标就是把 file 放进 fdt-&gt;fd 里面，完成 fd 与 file 的关联 */void fd_install(unsigned int fd, struct file *file)&#123;	struct files_struct *files = current-&gt;files;	struct fdtable *fdt;	rcu_read_lock_sched();	if (unlikely(files-&gt;resize_in_progress)) &#123;		rcu_read_unlock_sched();		spin_lock(&amp;files-&gt;file_lock);		fdt = files_fdtable(files);		BUG_ON(fdt-&gt;fd[fd] != NULL);		rcu_assign_pointer(fdt-&gt;fd[fd], file);		spin_unlock(&amp;files-&gt;file_lock);		return;	&#125;	/* coupled with smp_wmb() in expand_fdtable() */	smp_rmb();	fdt = rcu_dereference_sched(files-&gt;fdt);	/* 正常应该为这个里面应该为空，如果不为空，触发BUG */	BUG_ON(fdt-&gt;fd[fd] != NULL);	/* 将file放进fd二维指针指向的数组的fd位置，完成 fd 与 file 的关联 */	rcu_assign_pointer(fdt-&gt;fd[fd], file);	rcu_read_unlock_sched();&#125;


总结socket函数就是在内核中创建了一个socket_alloc结构，并且会根据传入的type、protocol来创建对应的sock结构。之后再创建一个文件对象，使之与socket相互关联。再选出一个最小未使用的fd，将文件对象存储到文件描述符列表fd位置处，将fd返给用户态。

libnetfilter_queue介绍在 Linux 防火墙中，iptables 本身并不处理数据包，它只是一个“规则描述工具”。真正的数据包裁决发生在内核 Netfilter 框架中。当我们通过iptables使用 -j NFQUEUE 参数下发规则时，本质上是告诉内核：匹配到该规则的 skb 不要立刻放行或拦截，而是进入NFQUEUE子系统，送往用户态程序，等待用户态来决定如何处理这个数据包。而libnetfilter_queue 就是 Linux 下 Netfilter 子系统提供的一个用户态开发库，专门用于用户态接收、分析、修改、处理，再决定是否放行&#x2F;拦截网络数据包，它是实现 NFQUEUE 功能的核心组件。
iptables 下发规则iptables规则下发到nfqueue，一般使用方法为：
iptables -I INPUT -j NFQUEUE --queue-num 0 

简而言之：就是下发了一条规则，向内核 filter表(默认)，注册到了INPUT链，当有数据包到INPUT链，转交给NFQUEUE子系统进行处理，并且入0号队列
iptables用户态调用流程iptables() └── do_command()      └── do_command4()           └── iptc_commit()                └── setsockopt(fd, SOL_IP, IPT_SO_SET_REPLACE, ...)

用户态主要做的就是： 

构造整张规则表的数据iptables 在用户态内部并不是“只构造一条规则”，而是会：解析当前系统中 已有的全部规则，然后将新规则插入到对应链（这里是 INPUT），再重新生成一整张完整的规则表数据结构，也就是说：iptables 在用户态做的是“整表重建”，不是“单条规则增量修改”。

通过 setsockopt 下发整张规则表给内核把包含所有链（INPUT、OUTPUT、FORWARD）所有规则、所有 match、所有 target（包括 NFQUEUE）的一整块内存，一次性发送给内核。然后iptables使命就结束了，后续的所有规则匹配与数据包处理，全部发生在内核中，iptables进程是不会参与任何一个数据包的处理的。


iptables内核态调用流程__x64_sys_setsockopt() └── do_sys_setsockopt()      └── __sys_setsockopt()          └── raw_setsockopt()               └── ip_setsockopt()                    └── nf_setsockopt()                        └── do_ipt_set_ctl()                             └── do_replace()                                  └── __do_replace()

内核态主要做的就是：

为整张规则表分配内核内存

newinfo = xt_alloc_table_info(tmp.size);if (!newinfo)	return -ENOMEM;

再将所有规则内容完整拷贝进内核

/* 从用户态拷贝 规则表头 */if (copy_from_sockptr(&amp;tmp, arg, sizeof(tmp)) != 0)	return -EFAULT; /* 从用户态拷贝 真正的规则内容 进内核 */if (copy_from_sockptr_offset(loc_cpu_entry, arg, sizeof(tmp),		tmp.size) != 0) &#123;	ret = -EFAULT;	goto free_newinfo;&#125;

解析并绑定目标（NFQUEUE 关键点）

