#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;#include &lt;errno.h&gt;#include &lt;string.h&gt;#include &lt;limits.h&gt;#include &lt;sys/socket.h&gt;#include &lt;arpa/inet.h&gt;/* 注意下这个头文件需要在arpa/inet.h之后包含，否则会报in_addr重定义 */#include &lt;linux/netfilter.h&gt;#include &lt;libnetfilter_queue/libnetfilter_queue.h&gt;/* 队列序号 */#define QUEUE_NUM   1/* 注意我们是hook input链，针对udp大包，需要 USHRT_MAX 才能完全存储 */#define MAX_BUF     USHRT_MAX#define QUEUE_MAXLEN 4096static int cb(struct nfq_q_handle *qh, struct nfgenmsg *nfmsg,              struct nfq_data *nfa, void *data)&#123;    unsigned char *payload = NULL;    int len = nfq_get_payload(nfa, &amp;payload);    printf(&quot;got packet, size = %d\n&quot;, len);    struct nfqnl_msg_packet_hdr *ph = nfq_get_msg_packet_hdr(nfa);    if (!ph) &#123;        printf(&quot;nfq_get_msg_packet_hdr failed\n&quot;);        return -1;    &#125;    /* 这里要注意，需要转成主机序 */    uint32_t id = ntohl(ph-&gt;packet_id);    return nfq_set_verdict(qh, id, NF_ACCEPT, 0, NULL);&#125;int main()&#123;    struct nfq_handle *h = NULL;    struct nfq_q_handle *qh = NULL;    int fd = -1;    int ret;    char buf[MAX_BUF] __attribute__ ((aligned));    h = nfq_open();    if (!h) &#123;        printf(&quot;nfq_open failed\n&quot;);        goto out;    &#125;    if (nfq_unbind_pf(h, AF_INET) &lt; 0) &#123;        printf(&quot;nfq_unbind_pf failed\n&quot;);        goto out;    &#125;    if (nfq_bind_pf(h, AF_INET) &lt; 0) &#123;        printf(&quot;nfq_bind_pf failed\n&quot;);        goto out;    &#125;    qh = nfq_create_queue(h, QUEUE_NUM, &amp;cb, NULL);    if (!qh) &#123;        printf(&quot;nfq_create_queue failed\n&quot;);        goto out;    &#125;    /* 拷贝整个数据包 */    ret = nfq_set_mode(qh, NFQNL_COPY_PACKET, 0xffff);    if (ret &lt; 0) &#123;        printf(&quot;nfq_set_mode failed\n&quot;);        goto out;    &#125;    /* 调大内核 nfqueue 环形队列长度，     * 这表示内核最大能缓存多少个尚未被用户态处理的包 */    ret = nfq_set_queue_maxlen(qh, QUEUE_MAXLEN);    if (ret &lt; 0) &#123;        printf(&quot;nfq_set_queue_maxlen failed\n&quot;);    &#125;    fd = nfq_fd(h);    if (fd &lt; 0) &#123;        printf(&quot;nfq_fd failed\n&quot;);        goto out;    &#125;    printf(&quot;nfqueue started, queue=%d\n&quot;, QUEUE_NUM);    while (1) &#123;        int n = recv(fd, buf, sizeof(buf), 0);        if (n &lt; 0) &#123;            if (errno == EINTR)                continue;            perror(&quot;recv&quot;);            break;        &#125;        if (n == 0) &#123;            printf(&quot;recv returned 0\n&quot;);            break;        &#125;        ret = nfq_handle_packet(h, buf, n);        if (ret &lt; 0) &#123;            printf(&quot;nfq_handle_packet error: %d\n&quot;, ret);        &#125;    &#125;out:    if (qh)        nfq_destroy_queue(qh);    if (h)        nfq_close(h);    return 0;&#125;

