glibc bind函数介绍我们使用的bind函数，原型如下。代码位置为：&#x2F;usr&#x2F;include&#x2F;x86_64-linux-gnu&#x2F;sys&#x2F;socket.h
int bind(int sockfd, struct sockaddr *my_addr, socklen_t addrlen);




参数
介绍



sockfd
socket返回的fd


my_addr
为套接字 sockfd 指定本地地址 my_addr


addrlen
my_addr的大小


而bind函数是glibc中提供的函数，我们看下glibc中的bind函数实现。代码位置在：glibc-2.41&#x2F;sysdeps&#x2F;unix&#x2F;sysv&#x2F;linux&#x2F;bind.c
#include &lt;sys/socket.h&gt;#include &lt;socketcall.h&gt;int__bind (int fd, __CONST_SOCKADDR_ARG addr, socklen_t len)&#123;#ifdef __ASSUME_BIND_SYSCALL  return INLINE_SYSCALL_CALL (bind, fd, addr.__sockaddr__, len);#else  return SOCKETCALL (bind, fd, addr.__sockaddr__, len, 0, 0, 0);#endif&#125;weak_alias (__bind, bind)

glibc中的bind函数也几乎什么都没做，可以理解为仅仅是内核bind系统调用(__do_sys_bind)的一个封装。
bind系统调用我们首先来看下bind系统调用的入口。可以看到__do_sys_bind，什么都没做，只是再次调用了__sys_bind。
SYSCALL_DEFINE3(bind, int, fd, struct sockaddr __user *, umyaddr, int, addrlen)&#123;	return __sys_bind(fd, umyaddr, addrlen);&#125;


在__sys_bind中，首先需要使用sockfd_lookup_light将fd转换出对应的socket结构，fd只是用户态使用的，在内核会对应一个socket结构。如果没找到，那代表传的是个垃圾fd，直接返回错误。如果找到了，代表传递的fd是有效的。调用move_addr_to_kernel，将传入的umyaddr转换到内核态的address结构中(因为传递的是地址，内核态是不能直接访问用户态的地址的)。然后过lsm socket_bind hook点，没有返回错误，那就直接调用inet_bind函数。
/* *  由 __do_sys_bind 调用 */int __sys_bind(int fd, struct sockaddr __user *umyaddr, int addrlen)&#123;	struct socket *sock;	struct sockaddr_storage address;	int err, fput_needed;	/* fd -&gt; socket */	sock = sockfd_lookup_light(fd, &amp;err, &amp;fput_needed);	if (sock) &#123;		/* copy_from_user */		err = move_addr_to_kernel(umyaddr, addrlen, &amp;address);		if (!err) &#123;			/* lsm socket_bind hook点 */			err = security_socket_bind(sock,						   (struct sockaddr *)&amp;address,						   addrlen);			if (!err) &#123;				/* inet_bind */				err = READ_ONCE(sock-&gt;ops)-&gt;bind(sock,						      (struct sockaddr *)						      &amp;address, addrlen);			&#125;		&#125;		fput_light(sock-&gt;file, fput_needed);	&#125;	return err;&#125;


sockfd_lookup_light中，就是将fd去current-&gt;files-&gt;fdt[fd]拿到文件对象，文件对象与socket是互指的，所以可以直接从文件对象的private_data中获取到socket指针。
/* 由 __sys_bind 调用 * 通过fd 查找到file，file的私有指针，就是其对应的socket */static struct socket *sockfd_lookup_light(int fd, int *err, int *fput_needed)&#123;	/* 根据传入的fd，从进程管理的fdtable中找到对应的file，这里 fd结构体 中的一个字段为file */	struct fd f = fdget(fd);	struct socket *sock;	*err = -EBADF;	if (f.file) &#123;		/* 从file的私有数据里拿到sock */		sock = sock_from_file(f.file);		if (likely(sock)) &#123;			*fput_needed = f.flags &amp; FDPUT_FPUT;			return sock;		&#125;		*err = -ENOTSOCK;		fdput(f);	&#125;	return NULL;&#125;static inline struct fd fdget(unsigned int fd)&#123;	return __to_fd(__fdget(fd));&#125;unsigned long __fdget(unsigned int fd)&#123;	return __fget_light(fd, FMODE_PATH);&#125;EXPORT_SYMBOL(__fdget);static unsigned long __fget_light(unsigned int fd, fmode_t mask)&#123;	struct files_struct *files = current-&gt;files;	struct file *file;	/*	 * If another thread is concurrently calling close_fd() followed	 * by put_files_struct(), we must not observe the old table	 * entry combined with the new refcount - otherwise we could	 * return a file that is concurrently being freed.	 *	 * atomic_read_acquire() pairs with atomic_dec_and_test() in	 * put_files_struct().	 */	if (atomic_read_acquire(&amp;files-&gt;count) == 1) &#123;		file = files_lookup_fd_raw(files, fd);		if (!file || unlikely(file-&gt;f_mode &amp; mask))			return 0;		return (unsigned long)file;	&#125; else &#123;		file = __fget(fd, mask);		if (!file)			return 0;		return FDPUT_FPUT | (unsigned long)file;	&#125;&#125;static inline struct file *files_lookup_fd_raw(struct files_struct *files, unsigned int fd)&#123;	struct fdtable *fdt = rcu_dereference_raw(files-&gt;fdt);	if (fd &lt; fdt-&gt;max_fds) &#123;		fd = array_index_nospec(fd, fdt-&gt;max_fds);		return rcu_dereference_raw(fdt-&gt;fd[fd]);	&#125;	return NULL;&#125;struct socket *sock_from_file(struct file *file)&#123;	/* 得确认这个file真的关联的是一个socket，才能取它的private_data */	if (file-&gt;f_op == &amp;socket_file_ops)		return file-&gt;private_data;	/* set in sock_alloc_file */	return NULL;&#125;EXPORT_SYMBOL(sock_from_file);


move_addr_to_kernel就是调用了copy_from_user，将用户态的地址结构拷贝到内核态。常用的就是copy_from_user、copy_to_user之类的。
int move_addr_to_kernel(void __user *uaddr, int ulen, struct sockaddr_storage *kaddr)&#123;	if (ulen &lt; 0 || ulen &gt; sizeof(struct sockaddr_storage))		return -EINVAL;	if (ulen == 0)		return 0;	if (copy_from_user(kaddr, uaddr, ulen))		return -EFAULT;	return audit_sockaddr(ulen, kaddr);&#125;


inet_bind从socket上取出对应的sock结构指针，然后调用inet_bind_sk。
/* 由 __sys_bind 调用 */int inet_bind(struct socket *sock, struct sockaddr *uaddr, int addr_len)&#123;	return inet_bind_sk(sock-&gt;sk, uaddr, addr_len);&#125;EXPORT_SYMBOL(inet_bind);

inet_bind_sk中，判断bind是否为空，不为空则调用bind绑定的函数，tcp、udp都是没有bind实现的(他们的绑定是get_port)。进行了地址长度校验，bpf 钩子点，然后调用__inet_bind。
/* 由 inet_bind 调用 */int inet_bind_sk(struct sock *sk, struct sockaddr *uaddr, int addr_len)&#123;	u32 flags = BIND_WITH_LOCK;	int err;	/* If the socket has its own bind function then use it. (RAW) 	 * tcp_prot 、 udp_prot 都没有 bind 实现，	 * ping_prot 、 raw_prot 有 bind 实现 */	if (sk-&gt;sk_prot-&gt;bind) &#123;		/* ping_bind 、 raw_bind */		return sk-&gt;sk_prot-&gt;bind(sk, uaddr, addr_len);	&#125;	/* 校验地址长度是否合法 */	if (addr_len &lt; sizeof(struct sockaddr_in))		return -EINVAL;	/* BPF prog is run before any checks are done so that if the prog	 * changes context in a wrong way it will be caught.	 * bpf	 */	err = BPF_CGROUP_RUN_PROG_INET_BIND_LOCK(sk, uaddr,						 CGROUP_INET4_BIND, &amp;flags);	if (err)		return err;	return __inet_bind(sk, uaddr, addr_len, flags);&#125;


在__inet_bind中：

首先对要绑定的地址的协议族进行检查。
然后对要绑定的地址类型做判断，判断是否是本机地址、多播、广播等。
接着检查是否允许 bind 非本地地址。
特权端口检查、权限检查
是否重复绑定端口检查
no port标志位检查
申请绑定port

/* 由 inet_bind_sk 调用 */int __inet_bind(struct sock *sk, struct sockaddr *uaddr, int addr_len, u32 flags)&#123;	struct sockaddr_in *addr = (struct sockaddr_in *)uaddr;	struct inet_sock *inet = inet_sk(sk);	struct net *net = sock_net(sk);	unsigned short snum;	int chk_addr_ret;	u32 tb_id = RT_TABLE_LOCAL;	int err;	/* 地址协议族校验 */	if (addr-&gt;sin_family != AF_INET) &#123;		/* Compatibility games : accept AF_UNSPEC (mapped to AF_INET)		 * only if s_addr is INADDR_ANY.		 */		err = -EAFNOSUPPORT;		/* 允许 AF_UNSPEC + INADDR_ANY，这是历史兼容行为 */		if (addr-&gt;sin_family != AF_UNSPEC ||		    addr-&gt;sin_addr.s_addr != htonl(INADDR_ANY))			goto out;	&#125;	/* 地址类型判断(本地/多播/广播) 	 * RTN_LOCAL		本机地址	 * RTN_MULTICAST	多播	 * RTN_BROADCAST	广播	 * RTN_UNICAST		单播	 * RTN_UNREACHABLE	不可达 	 */	tb_id = l3mdev_fib_table_by_index(net, sk-&gt;sk_bound_dev_if) ? : tb_id;	chk_addr_ret = inet_addr_type_table(net, addr-&gt;sin_addr.s_addr, tb_id);	/* Not specified by any standard per-se, however it breaks too	 * many applications when removed.  It is unfortunate since	 * allowing applications to make a non-local bind solves	 * several problems with systems using dynamic addressing.	 * (ie. your servers still start up even if your ISDN link	 *  is temporarily down)	 * 检查是否允许 bind 非本地地址，	 * 解决DHCP/动态地址/服务先启动的问题，否则服务器必须等IP配好才能启动，体验差	 */	err = -EADDRNOTAVAIL;	if (!inet_addr_valid_or_nonlocal(net, inet, addr-&gt;sin_addr.s_addr,	                                 chk_addr_ret))		goto out;	/* 将要绑定的端口转换成主机序 */	snum = ntohs(addr-&gt;sin_port);	/* 特权端口检查，绑定特权端口，必须要有满足权限限制，否则go out */	err = -EACCES;	if (!(flags &amp; BIND_NO_CAP_NET_BIND_SERVICE) &amp;&amp;	    snum &amp;&amp; inet_port_requires_bind_service(net, snum) &amp;&amp;	    !ns_capable(net-&gt;user_ns, CAP_NET_BIND_SERVICE))		goto out;	/*      We keep a pair of addresses. rcv_saddr is the one	 *      used by hash lookups, and saddr is used for transmit.	 *	 *      In the BSD API these are the same except where it	 *      would be illegal to use them (mult