inet_csk_get_port就是判断传入的端口是否为0，为了就走inet_csk_find_open_port，自动选取合适的端口。不为0就是指定要绑定的端口，直接计算hash，看是否已有该hash对应的桶，没有则创建，有则判断网络命名空间、port、l3mdev是否匹配。并且如果是指定的端口是需要进行冲突检测，随机端口因为选取时就已经做了冲突检测，所以这里不再需要额外做冲突检测。如果没有冲突，就将这个sk插入到bhash、bhash2哈希表的对应哈希桶的owners上，owners也是个哈希表。 
/* * __inet_bind 、 inet_csk_listen_start  都会调用这个函数 * __inet_bind 是来 bind 绑定端口的 * inet_csk_listen_start 是 listen 来检查下端口是否绑定的 */int inet_csk_get_port(struct sock *sk, unsigned short snum)&#123;	/* 获取该sk所在命名空间里，用来管理 各种 tcp 套接字 的哈希组合结构 */	struct inet_hashinfo *hinfo = tcp_or_dccp_get_hashinfo(sk);	bool reuse = sk-&gt;sk_reuse &amp;&amp; sk-&gt;sk_state != TCP_LISTEN;	/* 用来标识，随机分配端口时，是否找到了合适的端口 */	bool found_port = false;	bool check_bind_conflict = true;	/* 用来标识是否在 bhash 、bhash2 上创建了新哈希桶 */	bool bhash_created = false, bhash2_created = false;	int ret = -EADDRINUSE;	int port = snum;	int l3mdev;	/* 端口 在 bhash 、bhash2 上对应的 哈希槽 */	struct inet_bind_hashbucket *head, *head2;	/* 端口 在 bhash 、bhash2 上对应的 哈希桶 */	struct inet_bind_bucket *tb = NULL;	struct inet_bind2_bucket *tb2 = NULL;	/* 用来标识是否持有了bhash2上哈希槽的锁 */	bool head2_lock_acquired = false;	struct net *net = sock_net(sk);	l3mdev = inet_sk_bound_l3mdev(sk);	/* 如果没有指定端口，就是想让内核给它随机绑定一个 */	if (!port) &#123;		/* 在内核限制的端口范围内，随机找端口，		 * 找到了合适端口，则能找到其对应的 bhash 上的哈希槽， 		 * 没找到合适端口，则返回空 */		head = inet_csk_find_open_port(sk, &amp;tb, &amp;tb2, &amp;head2, &amp;port);		if (!head)			return ret;		head2_lock_acquired = true;		/* 如果port对应的tb、tb2哈希桶都存在，直接跳转到success */		if (tb &amp;&amp; tb2)			goto success;			/* 随机选出的端口，inet_csk_find_open_port已经做过冲突检测了，		 * 所以这里置true，后面会跳过很多冲突检测的逻辑 */		found_port = true;	&#125; else &#123;		/* 指定了端口，直接计算 bhash，拿到 bhash 哈希表上的对应哈希桶 */		head = &amp;hinfo-&gt;bhash[inet_bhashfn(net, port, hinfo-&gt;bhash_size)];		spin_lock_bh(&amp;head-&gt;lock);		/* 遍历bhash哈希表上面对应的哈希槽，是否有 相同命名空间 且 端口相同的 且 l3mdev 相同的		 * 有则直接break，此时tb不为空，		 * 没有则会遍历完这个槽，此时tb为空 */		inet_bind_bucket_for_each(tb, &amp;head-&gt;chain)			if (inet_bind_bucket_match(tb, net, port, l3mdev))				break;	&#125;	if (!tb) &#123;		/* 在 bhash 哈希表上创建哈希桶，注意这里创建完就已经加到了bhash里 */		tb = inet_bind_bucket_create(hinfo-&gt;bind_bucket_cachep, net,					     head, port, l3mdev);		if (!tb)			goto fail_unlock;		bhash_created = true;	&#125;	/* 走到这里，只有是指定的端口，found_port才会是false */	if (!found_port) &#123;		/* 当前是否有其它socket持有tb这个哈希桶(是否使用了这个端口) */		if (!hlist_empty(&amp;tb-&gt;owners)) &#123;			/* 设置了reuse，那就不再检查冲突 */			if (sk-&gt;sk_reuse == SK_FORCE_REUSE ||	/* 强制重用 */			    (tb-&gt;fastreuse &gt; 0 &amp;&amp; reuse) ||		/* 快速重用且当前socket允许重用 */			    sk_reuseport_match(tb, sk))			/* 端口重用匹配 */				check_bind_conflict = false;		&#125;		/* 检查冲突标志位开启，并且 sk_rcv_saddr 不是 ANY，才去检查冲突 */		if (check_bind_conflict &amp;&amp; inet_use_bhash2_on_bind(sk)) &#123;			if (inet_bhash2_addr_any_conflict(sk, port, l3mdev, true, true))				goto fail_unlock;		&#125;		/* 走到这里的，是没获取过head2、tb2的，去获取下,		 * 根据 sk_rcv_saddr 、port，直接计算 hash2，拿到 bhash 哈希表上的对应哈希桶 */		head2 = inet_bhashfn_portaddr(hinfo, sk, net, port);		spin_lock(&amp;head2-&gt;lock);		head2_lock_acquired = true;		tb2 = inet_bind2_bucket_find(head2, net, port, l3mdev, sk);	&#125;	if (!tb2) &#123;		/* 在 bhash2 哈希表上创建哈希桶，注意这里创建完就已经加到了bhash2里 */		tb2 = inet_bind2_bucket_create(hinfo-&gt;bind2_bucket_cachep,					       net, head2, port, l3mdev, sk);		if (!tb2)			goto fail_unlock;		bhash2_created = true;	&#125;	/* 只有是指定的端口，found_port才会是false，并且没开reuse，再次检查冲突 */	if (!found_port &amp;&amp; check_bind_conflict) &#123;		if (inet_csk_bind_conflict(sk, tb, tb2, true, true))			goto fail_unlock;	&#125;success:	inet_csk_update_fastreuse(tb, sk);	/* 真正的将sk插入到哈希表的哈希桶的owners上，owners也是个哈希表 */	if (!inet_csk(sk)-&gt;icsk_bind_hash)		inet_bind_hash(sk, tb, tb2, port);	WARN_ON(inet_csk(sk)-&gt;icsk_bind_hash != tb);	WARN_ON(inet_csk(sk)-&gt;icsk_bind2_hash != tb2);	ret = 0;fail_unlock:	if (ret) &#123;		/* 失败了，但是bhash、bhash2之前可能创建了新哈希桶，那就释放下 */		if (bhash_created)			inet_bind_bucket_destroy(hinfo-&gt;bind_bucket_cachep, tb);		if (bhash2_created)			inet_bind2_bucket_destroy(hinfo-&gt;bind2_bucket_cachep, tb2);	&#125;	/* 如果对head2已经加锁了，这里一定要解锁 */	if (head2_lock_acquired)		spin_unlock(&amp;head2-&gt;lock);	spin_unlock_bh(&amp;head-&gt;lock);	return ret;&#125;EXPORT_SYMBOL_GPL(inet_csk_get_port);


inet_csk_find_open_port在本地端口范围内随机挑选端口，同时在 bhash（端口维度）和 bhash2（端口+地址维度）上进行冲突检测，若检测通过，则 在持锁状态下返回对应的 hashbucket 和端口号，来保证后续 inet_csk_get_port() 绑定过程的原子性。
/* * Find an open port number for the socket.  Returns with the * inet_bind_hashbucket locks held if successful. * 由 inet_csk_get_port 调用 */static struct inet_bind_hashbucket *inet_csk_find_open_port(const struct sock *sk, struct inet_bind_bucket **tb_ret,			struct inet_bind2_bucket **tb2_ret,			struct inet_bind_hashbucket **head2_ret, int *port_ret)&#123;	struct inet_hashinfo *hinfo = tcp_or_dccp_get_hashinfo(sk);	int i, low, high, attempt_half, port, l3mdev;	struct inet_bind_hashbucket *head, *head2;	struct net *net = sock_net(sk);	struct inet_bind2_bucket *tb2;	struct inet_bind_bucket *tb;	u32 remaining, offset;	bool relax = false;	l3mdev = inet_sk_bound_l3mdev(sk);ports_exhausted:	attempt_half = (sk-&gt;sk_reuse == SK_CAN_REUSE) ? 1 : 0;other_half_scan:	inet_sk_get_local_port_range(sk, &amp;low, &amp;high);	high++; /* [32768, 60999] -&gt; [32768, 61000[ */	if (high - low &lt; 4)		attempt_half = 0;	if (attempt_half) &#123;		int half = low + (((high - low) &gt;&gt; 2) &lt;&lt; 1);		if (attempt_half == 1)			high = half;		else			low = half;	&#125;	remaining = high - low;	if (likely(remaining &gt; 1))		remaining &amp;= ~1U;	offset = get_random_u32_below(remaining);	/* __inet_hash_connect() favors ports having @low parity	 * We do the opposite to not pollute connect() users.	 */	offset |= 1U;other_parity_scan:	port = low + offset;	for (i = 0; i &lt; remaining; i += 2, port += 2) &#123;		if (unlikely(port &gt;= high))			port -= remaining;		if (inet_is_local_reserved_port(net, port))			continue;		head = &amp;hinfo-&gt;bhash[inet_bhashfn(net, port,						  hinfo-&gt;bhash_size)];		spin_lock_bh(&amp;head-&gt;lock);		if (inet_use_bhash2_on_bind(sk)) &#123;			if (inet_bhash2_addr_any_conflict(sk, port, l3mdev, relax, false))				goto next_port;		&#125;		head2 = inet_bhashfn_portaddr(hinfo, sk, net, port);		spin_lock(&amp;head2-&gt;lock);		tb2 = inet_bind2_bucket_find(head2, net, port, l3mdev, sk);		inet_bind_bucket_for_each(tb, &amp;head-&gt;chain)			if (inet_bind_bucket_match(tb, net, port, l3mdev)) &#123;				if (!inet_csk_bind_conflict(sk, tb, tb2,							    relax, false))					goto success;				spin_unlock(&amp;head2-&gt;lock);				goto next_port;			&#125;		tb = NULL;		goto success;next_port:		spin_unlock_bh(&amp;head-&gt;lock);		cond_resched();	&#125;	offset--;	if (!(offset &amp; 1))		goto other_parity_scan;	if (attempt_half == 1) &#123;		/* OK we now try the upper half of the range */		attempt_half = 2;		goto other_half_scan;	&#125;	if (READ_ONCE(net-&gt;ipv4.sysctl_ip_autobind_reuse) &amp;&amp; !relax) &#123;		/* We still have a chance to connect to different destinations */		relax = true;		goto ports_exhausted;	&#125;	return NULL;success:	*port_ret = port;	*tb_ret = tb;	*tb2_ret = tb2;	*head2_ret = head2;	return head;&#125;


总结bind() 在内核中首先校验地址合法性与权限，然后根据 socket 状态决定是否立即分配端口。端口绑定通过 bhash（端口维度）和 bhash2（地址+端口维度）进行冲突检测，并结合 SO_REUSEADDR&#x2F;SO_REUSEPORT&#x2F;fastreuse等策略决定是否允许共用端口。最终，socket 被安全地插入绑定哈希表，完成本地地址与端口的占用。
